"use strict";(self.webpackChunkdeveloper_playcanvas_com=self.webpackChunkdeveloper_playcanvas_com||[]).push([["95514"],{83053(e){e.exports=JSON.parse('{"tag":{"label":"camera","permalink":"/tags/camera","allTagsPath":"/tags","count":25,"items":[{"id":"tutorials/360-lookaround-camera","title":"360 lookaround camera","description":"Use mouse and touch to rotate the camera and look around a scene for a panoramic or first-person style viewer.","permalink":"/tutorials/360-lookaround-camera"},{"id":"tutorials/basic-cameras","title":"Basic Cameras","description":"Add camera entities so your scene renders to the screen and learn the minimum editor setup for a visible view.","permalink":"/tutorials/basic-cameras"},{"id":"tutorials/billboards","title":"Billboards","description":"Keep planes facing the camera for trees, flares, and sprites that always show their front toward the viewer.","permalink":"/tutorials/billboards"},{"id":"tutorials/camera-following-a-path","title":"Camera following a path","description":"Animate a camera along a spline path through waypoints for flythroughs and guided cinematic motion.","permalink":"/tutorials/camera-following-a-path"},{"id":"tutorials/camera-model-masking","title":"Camera model masking","description":"Use camera and light mask groups so specific lights and views only affect chosen models in layered scenes.","permalink":"/tutorials/camera-model-masking"},{"id":"tutorials/capturing-a-screenshot","title":"Capturing a screenshot","description":"Render from a camera to a texture and export pixels as a PNG for captures and sharing from your app.","permalink":"/tutorials/capturing-a-screenshot"},{"id":"tutorials/explosion-particle-effect","title":"Explosion Particle Effect","description":"Layer particle emitters with camera shake to sell an explosion impact and debris burst in real time.","permalink":"/tutorials/explosion-particle-effect"},{"id":"tutorials/first-person-movement","title":"First Person Movement","description":"Implement first-person movement with rigidbody forces, mouse look, and an optional child camera rig.","permalink":"/tutorials/first-person-movement"},{"id":"tutorials/first-person-shooter-starter-kit","title":"First Person Shooter Starter Kit","description":"Extend first-person controls with jumping and navigation as a starter for FPS-style movement prototypes.","permalink":"/tutorials/first-person-shooter-starter-kit"},{"id":"tutorials/information-hotspots","title":"Information hotspots","description":"Place clickable hotspots in the 3D view that open info panels using raycasts and screen overlays.","permalink":"/tutorials/information-hotspots"},{"id":"tutorials/locking-the-mouse","title":"Locking the mouse","description":"Request pointer lock on click to capture the mouse for first-person look, hiding the cursor while movement drives the camera.","permalink":"/tutorials/locking-the-mouse"},{"id":"tutorials/more-cameras","title":"More Cameras","description":"Script camera components to change FOV, position, and active camera at runtime for zooming, cuts, and multi-camera setups.","permalink":"/tutorials/more-cameras"},{"id":"tutorials/multiple-camera-layers","title":"Multiple Camera Layers","description":"Combine multiple cameras and render layers to mix screen-space UI with world-space elements in one PlayCanvas scene.","permalink":"/tutorials/multiple-camera-layers"},{"id":"tutorials/multiple-viewport-rendering","title":"Multiple Viewport Rendering","description":"Split the canvas into separate camera viewports by adjusting each camera rectangle for picture-in-picture or split-screen views.","permalink":"/tutorials/multiple-viewport-rendering"},{"id":"tutorials/orbit-camera","title":"Orbit camera","description":"Implement an orbit camera with mouse and touch, including scroll-wheel zoom and pinch-to-zoom around a focal entity.","permalink":"/tutorials/orbit-camera"},{"id":"tutorials/pan-camera-to-target","title":"Pan Camera to Target","description":"Smoothly move and aim the camera toward a world-space target so clicks or events frame important locations in the scene.","permalink":"/tutorials/pan-camera-to-target"},{"id":"tutorials/raycast-with-camera-viewports","title":"Raycast with Camera Viewports","description":"Convert pointer coordinates into per-camera rays when using split viewports so picking hits the correct 3D region in each pane.","permalink":"/tutorials/raycast-with-camera-viewports"},{"id":"tutorials/render-3d-world-to-ui","title":"Render 3D World to UI","description":"Render a 3D preview with a dedicated camera into UI elements such as inventory icons or character selection panels.","permalink":"/tutorials/render-3d-world-to-ui"},{"id":"tutorials/smooth-camera-movement","title":"Smooth camera movement","description":"Ease the camera between positions and orientations each frame using vector lerp and quaternion slerp for cinematic motion.","permalink":"/tutorials/smooth-camera-movement"},{"id":"tutorials/third-person-controller","title":"Third Person Controller","description":"Follow a controllable character with a chase camera while handling input and physics for a basic third-person movement rig.","permalink":"/tutorials/third-person-controller"},{"id":"tutorials/webxr-ar-dom-overlay","title":"WebXR AR: DOM Overlay","description":"Combine WebXR AR with the DOM overlay API to place styled HTML/CSS UI above the camera feed without custom WebGL text.","permalink":"/tutorials/webxr-ar-dom-overlay"},{"id":"tutorials/webxr-ar-hit-test","title":"WebXR AR: Hit Test","description":"Cast rays into real-world geometry with the WebXR hit-test API to anchor virtual objects on detected floors and tables.","permalink":"/tutorials/webxr-ar-hit-test"},{"id":"tutorials/webxr-ar-image-tracking","title":"WebXR: AR Image Tracking","description":"Track printed reference images in AR and align 3D content to their pose using the WebXR image-tracking extension.","permalink":"/tutorials/webxr-ar-image-tracking"},{"id":"tutorials/webxr-plane-detection","title":"WebXR: Plane Detection","description":"Subscribe to WebXR plane detection updates to visualize floor and table estimates for anchoring content to real surfaces.","permalink":"/tutorials/webxr-plane-detection"},{"id":"tutorials/world-to-ui-screen-space","title":"World to UI Screen space","description":"Project 3D world positions into screen-space anchors so labels and markers track moving objects on the 2D overlay.","permalink":"/tutorials/world-to-ui-screen-space"}],"unlisted":false}}')}}]);